  { preHandler: [authenticate, authorize(['admin', 'moderator'])] },
  async (request, reply) => {
    const { entity, id } = request.params;
    const { pinned, featured, locked, archived } = request.body || {};

    const tableMap = {
      sections: 'forum_sections',
      threads: 'forum_threads',
      posts: 'forum_posts',
    };
    const table = tableMap[entity];
    if (!table) {
      return reply.code(400).send({ error: 'entity must be sections|threads|posts' });
    }

    const res = await query(
      `UPDATE ${table}
       SET pinned = COALESCE($2, pinned),
           featured = COALESCE($3, featured),
           locked = COALESCE($4, locked),
           archived = COALESCE($5, archived),
           updated_at = CASE WHEN EXISTS (
             SELECT 1 FROM information_schema.columns
             WHERE table_name = $1 AND column_name = 'updated_at'
           ) THEN NOW() ELSE NULL END
       WHERE id = $6
       RETURNING *`,
      [table, pinned, featured, locked, archived, id]
    );

    if (!res.rows.length) {
      return reply.code(404).send({ error: 'Entity not found' });
    }

    await audit(request.user.id, 'moderate', table, id, { pinned, featured, locked, archived });
    return res.rows[0];
  }
);

async function start() {
  const port = Number(process.env.PORT || 3000);
  const host = '0.0.0.0';
  try {
    await app.listen({ port, host });
  } catch (err) {
    app.log.error(err);
    process.exit(1);
  }
}

const shutdown = async () => {
  await pool.end();
  process.exit(0);
};

process.on('SIGINT', shutdown);
process.on('SIGTERM', shutdown);

start();
