  }, [token, selectedSection]);

  useEffect(() => {
    if (!token || !selectedThread) return;
    api(`/api/forum/threads/${selectedThread}/posts`)
      .then((r) => setPosts(r.items || []))
      .catch((e) => setError(e.message));
  }, [token, selectedThread]);

  async function loginSubmit(e) {
    e.preventDefault();
    setError('');
    setNotice('');
    try {
      const res = await api('/api/auth/login', {
        method: 'POST',
        body: JSON.stringify(loginForm),
      });
      setToken(res.token);
      setUser(res.user);
      setNotice(`Logged in as ${res.user.username} (${res.user.role})`);
    } catch (err) {
      setError(err.message);
    }
  }

  async function createScript(e) {
    e.preventDefault();
    setError('');

    if (scriptForm.min_party_size > scriptForm.max_party_size) {
      setError('Script validation: min party size must be <= max party size.');
      return;
    }

    try {
      await api('/api/scripts', {
        method: 'POST',
        body: JSON.stringify({
          ...scriptForm,
          required_props: scriptForm.required_props
            .split(',')
            .map((v) => v.trim())
            .filter(Boolean),
          tags: scriptForm.tags
            .split(',')
            .map((v) => v.trim())
            .filter(Boolean),
        }),
      });
      setScriptForm({
        title: '',
        description: '',
        difficulty: 3,
        duration_minutes: 60,
        min_party_size: 2,
        max_party_size: 6,
        required_props: '',
        status: 'active',
        tags: '',
      });
      await refreshAll();
      setNotice('Script created.');
    } catch (err) {
      setError(err.message);
    }
  }

  async function toggleScriptStatus(script) {
    const toStatus = script.status === 'active' ? 'paused' : 'active';
    if (!window.confirm(`Change script "${script.title}" to ${toStatus}?`)) return;

    try {
      await api(`/api/scripts/${script.id}`, {
        method: 'PATCH',
        body: JSON.stringify({ status: toStatus }),
      });
      await refreshAll();
      setNotice(`Script moved to ${toStatus}.`);
      setUndoAction({
        label: `Undo script status (${script.title})`,
        run: async () => {
          await api(`/api/scripts/${script.id}`, {
            method: 'PATCH',
            body: JSON.stringify({ status: script.status }),
          });
          await refreshAll();
          setNotice('Undo complete.');
        },
      });
    } catch (err) {
      setError(err.message);
    }
  }

  async function createRoom(e) {
    e.preventDefault();
    if (roomForm.capacity <= 0) {
      setError('Room capacity must be greater than 0.');
      return;
    }
    try {
      await api('/api/resources/rooms', {
        method: 'POST',
        body: JSON.stringify(roomForm),
      });
      setRoomForm({ name: '', room_type: 'room', capacity: 4 });
      await refreshAll();
      setNotice('Resource created.');
    } catch (err) {
      setError(err.message);
    }
  }

  async function createBooking(e) {
    e.preventDefault();
    if (!bookingForm.script_id || !bookingForm.room_id) {
      setError('Booking validation: select both a script and a room.');
      return;
    }
    if (new Date(bookingForm.end_at) <= new Date(bookingForm.start_at)) {
      setError('Booking validation: end time must be after start time.');
      return;
    }

    try {
      await api('/api/bookings', {
        method: 'POST',
        body: JSON.stringify(bookingForm),
      });
      await refreshAll();
      setNotice('Booking created.');
    } catch (err) {
      setError(err.message);
    }
  }

  async function updateBookingStatus(item, status) {
    if (!window.confirm(`Set booking for ${item.customer_name} to ${status}?`)) return;
    try {
      await api(`/api/bookings/${item.id}/status`, {
        method: 'PATCH',
        body: JSON.stringify({ status }),
      });
      await refreshAll();
      setUndoAction({
        label: `Undo booking status (${item.customer_name})`,
        run: async () => {
          await api(`/api/bookings/${item.id}/status`, {
            method: 'PATCH',
            body: JSON.stringify({ status: item.status }),
          });
          await refreshAll();
          setNotice('Undo complete.');
        },
      });
    } catch (err) {
      setError(err.message);
    }
  }

  async function createSection(e) {
    e.preventDefault();
    try {
      await api('/api/forum/sections', {
        method: 'POST',
        body: JSON.stringify(sectionForm),
      });
      setSectionForm({ name: '', description: '' });
      await refreshAll();
    } catch (err) {
      setError(err.message);
    }
  }

  async function createThread(e) {
    e.preventDefault();
    if (!selectedSection) {
      setError('Pick a section first.');
      return;
    }
    try {
      await api('/api/forum/threads', {
        method: 'POST',
        body: JSON.stringify({ ...threadForm, section_id: selectedSection }),
      });
      setThreadForm({ title: '', body: '' });
      const res = await api(`/api/forum/threads?section_id=${selectedSection}`);
      setThreads(res.items || []);
    } catch (err) {
      setError(err.message);
    }
  }

  async function createPost(e) {
    e.preventDefault();
    if (!selectedThread) {
      setError('Pick a thread first.');
      return;
    }
    try {
      await api('/api/forum/posts', {
        method: 'POST',
        body: JSON.stringify({
          thread_id: selectedThread,
          body: postForm.body,
          parent_post_id: postForm.parent_post_id || null,
        }),
      });
      setPostForm({ body: '', parent_post_id: '' });
      const res = await api(`/api/forum/threads/${selectedThread}/posts`);
      setPosts(res.items || []);
    } catch (err) {
      setError(err.message);
    }
  }

  async function moderate(entity, id, field, value) {
    if (!window.confirm(`Apply moderation change: ${field}=${String(value)}?`)) return;
    try {
      await api(`/api/forum/${entity}/${id}/moderation`, {
        method: 'PATCH',
        body: JSON.stringify({ [field]: value }),
      });
      await refreshAll();
      if (selectedSection) {
        const t = await api(`/api/forum/threads?section_id=${selectedSection}`);
        setThreads(t.items || []);
      }
      if (selectedThread) {
        const p = await api(`/api/forum/threads/${selectedThread}/posts`);
        setPosts(p.items || []);
      }
      setNotice('Moderation state updated.');
    } catch (err) {
      setError(err.message);
    }
  }

  const navButtons = useMemo(
    () =>
      tabs.map((tab) => (
        <button
          key={tab}
          onClick={() => setActiveTab(tab)}
          className={classes(
            'rounded-md px-3 py-2 text-sm capitalize transition',
            activeTab === tab ? 'bg-black text-white' : 'bg-slate-800 text-slate-200 hover:bg-slate-700'
          )}
        >
          {tab}
        </button>
      )),
    [activeTab]
  );

  if (!token) {
    return (
      <div className="min-h-screen bg-slate-950 text-slate-100 p-6">
        <div className="mx-auto mt-20 max-w-md rounded-xl border border-slate-700 bg-slate-900 p-6 shadow-2xl">
          <h1 className="text-2xl font-semibold">Operations Login</h1>
          <p className="mt-2 text-sm text-slate-300">Admin session supports RBAC, lockout, and idle timeout rules.</p>
          <form className="mt-6 space-y-3" onSubmit={loginSubmit}>
            <input
              className="w-full rounded-md border border-slate-600 bg-slate-800 px-3 py-2"
              value={loginForm.username}
              onChange={(e) => setLoginForm({ ...loginForm, username: e.target.value })}
              placeholder="username"
            />
            <input
              className="w-full rounded-md border border-slate-600 bg-slate-800 px-3 py-2"
              value={loginForm.password}
              onChange={(e) => setLoginForm({ ...loginForm, password: e.target.value })}
              placeholder="password"
              type="password"
            />
            <button className="w-full rounded-md bg-black px-4 py-2 text-white">Sign in</button>
          </form>
          {error && <p className="mt-3 text-sm text-red-300">{error}</p>}
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100">
      <header className="border-b border-slate-700 bg-slate-900/90 px-4 py-4">
        <div className="mx-auto flex max-w-7xl flex-wrap items-center justify-between gap-3">
          <div>
            <h1 className="text-xl font-bold">Task3 Vertical Slice Console</h1>
            <p className="text-xs text-slate-300">{user?.username} · {user?.role}</p>
          </div>
          <div className="flex flex-wrap gap-2">{navButtons}</div>
        </div>
      </header>

      <main className="mx-auto max-w-7xl p-4">
        {error && <div className="mb-3 rounded-md border border-red-400/40 bg-red-950/60 p-2 text-sm text-red-200">{error}</div>}
        {notice && <div className="mb-3 rounded-md border border-emerald-400/40 bg-emerald-950/60 p-2 text-sm text-emerald-200">{notice}</div>}
        {undoAction && (
          <div className="mb-3 flex items-center justify-between rounded-md border border-amber-400/40 bg-amber-950/60 p-2 text-sm text-amber-100">
            <span>{undoAction.label}</span>
            <button
              className="rounded-md bg-black px-3 py-1 text-white"
              onClick={async () => {
                try {
                  await undoAction.run();
                  setUndoAction(null);
                } catch (e) {
                  setError(e.message);
                }
              }}
            >
              Undo
            </button>
          </div>
        )}

        {activeTab === 'scripts' && (
          <section className="grid gap-4 md:grid-cols-2">
            <form onSubmit={createScript} className="rounded-lg border border-slate-700 bg-slate-900 p-4 space-y-2">
              <h2 className="text-lg font-semibold">Script Manager</h2>
              <input className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" placeholder="title" value={scriptForm.title} onChange={(e) => setScriptForm({ ...scriptForm, title: e.target.value })} />
              <textarea className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" placeholder="description" value={scriptForm.description} onChange={(e) => setScriptForm({ ...scriptForm, description: e.target.value })} />
              <div className="grid grid-cols-2 gap-2">
                <input className="rounded border border-slate-600 bg-slate-800 px-2 py-1" type="number" min="1" max="5" value={scriptForm.difficulty} onChange={(e) => setScriptForm({ ...scriptForm, difficulty: Number(e.target.value) })} />
                <input className="rounded border border-slate-600 bg-slate-800 px-2 py-1" type="number" min="1" value={scriptForm.duration_minutes} onChange={(e) => setScriptForm({ ...scriptForm, duration_minutes: Number(e.target.value) })} />
                <input className="rounded border border-slate-600 bg-slate-800 px-2 py-1" type="number" min="1" value={scriptForm.min_party_size} onChange={(e) => setScriptForm({ ...scriptForm, min_party_size: Number(e.target.value) })} />
                <input className="rounded border border-slate-600 bg-slate-800 px-2 py-1" type="number" min="1" value={scriptForm.max_party_size} onChange={(e) => setScriptForm({ ...scriptForm, max_party_size: Number(e.target.value) })} />
              </div>
              <input className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" placeholder="required props (comma-separated)" value={scriptForm.required_props} onChange={(e) => setScriptForm({ ...scriptForm, required_props: e.target.value })} />
              <input className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" placeholder="tags (comma-separated)" value={scriptForm.tags} onChange={(e) => setScriptForm({ ...scriptForm, tags: e.target.value })} />
              <select className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" value={scriptForm.status} onChange={(e) => setScriptForm({ ...scriptForm, status: e.target.value })}>
                <option value="active">active</option>
                <option value="paused">paused</option>
              </select>
              <button disabled={!isAdmin} className="rounded-md bg-black px-4 py-2 text-white disabled:opacity-40">Create Script</button>
              {!isAdmin && <p className="text-xs text-amber-300">Admin role required to create/update scripts.</p>}
            </form>

            <div className="rounded-lg border border-slate-700 bg-slate-900 p-4">
              <h3 className="mb-3 text-lg font-semibold">Scripts</h3>
              <div className="space-y-2">
                {scripts.map((s) => (
                  <div key={s.id} className="rounded border border-slate-700 bg-slate-800 p-3">
                    <div className="flex items-center justify-between">
                      <p className="font-medium">{s.title}</p>
                      <span className="text-xs text-slate-300">{s.status}</span>
                    </div>
                    <p className="text-xs text-slate-300">Difficulty {s.difficulty} · {s.duration_minutes} mins · Party {s.min_party_size}-{s.max_party_size}</p>
                    <p className="text-xs text-slate-400">Props: {(s.required_props || []).join(', ') || 'none'} · Tags: {(s.tags || []).join(', ') || 'none'}</p>
                    <button disabled={!isAdmin} className="mt-2 rounded-md bg-black px-3 py-1 text-sm text-white disabled:opacity-40" onClick={() => toggleScriptStatus(s)}>Toggle active/paused</button>
                  </div>
                ))}
              </div>
            </div>
          </section>
        )}

        {activeTab === 'resources' && (
          <section className="grid gap-4 md:grid-cols-2">
            <div className="space-y-4">
              <form onSubmit={createRoom} className="rounded-lg border border-slate-700 bg-slate-900 p-4 space-y-2">
                <h2 className="text-lg font-semibold">Resource Scheduler: Rooms/Tables</h2>
                <input className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" placeholder="name" value={roomForm.name} onChange={(e) => setRoomForm({ ...roomForm, name: e.target.value })} />
                <select className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" value={roomForm.room_type} onChange={(e) => setRoomForm({ ...roomForm, room_type: e.target.value })}>
                  <option value="room">room</option>
                  <option value="table">table</option>
                </select>
                <input className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" type="number" min="1" value={roomForm.capacity} onChange={(e) => setRoomForm({ ...roomForm, capacity: Number(e.target.value) })} />
                <button disabled={!isAdmin} className="rounded-md bg-black px-4 py-2 text-white disabled:opacity-40">Create Resource</button>
              </form>

              <div className="rounded-lg border border-slate-700 bg-slate-900 p-4">
                <h3 className="text-lg font-semibold">Business Hours</h3>
                <ul className="mt-2 space-y-1 text-sm">
                  {businessHours.map((h) => (
                    <li key={h.id} className="rounded border border-slate-700 bg-slate-800 px-2 py-1">
                      Day {h.weekday}: {h.is_closed ? 'Closed' : `${h.open_time} - ${h.close_time}`}
                    </li>
                  ))}
                </ul>
              </div>
            </div>

            <div className="rounded-lg border border-slate-700 bg-slate-900 p-4">
              <h3 className="text-lg font-semibold">Availability</h3>
              <p className="text-xs text-slate-300 mb-2">Host schedules + resources</p>
              <ul className="space-y-2">
                {rooms.map((r) => (
                  <li key={r.id} className="rounded border border-slate-700 bg-slate-800 p-2 text-sm">
                    {r.name} ({r.room_type}) · capacity {r.capacity}
                  </li>
                ))}
              </ul>
              <h4 className="mt-4 text-sm font-semibold">Host schedules</h4>
              <ul className="mt-2 space-y-1 text-xs text-slate-300">
                {hostSchedules.map((h) => (
                  <li key={h.id} className="rounded border border-slate-700 bg-slate-800 px-2 py-1">
                    {h.host_username} · {h.room_name} · day {h.weekday} · {h.start_time}-{h.end_time}
                  </li>
                ))}
              </ul>
            </div>
          </section>
        )}

        {activeTab === 'bookings' && (
          <section className="grid gap-4 md:grid-cols-2">
            <form onSubmit={createBooking} className="rounded-lg border border-slate-700 bg-slate-900 p-4 space-y-2">
              <h2 className="text-lg font-semibold">Bookings</h2>
              <select className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" value={bookingForm.script_id} onChange={(e) => setBookingForm({ ...bookingForm, script_id: e.target.value })}>
                <option value="">Select script</option>
                {scripts.map((s) => <option key={s.id} value={s.id}>{s.title}</option>)}
              </select>
              <select className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" value={bookingForm.room_id} onChange={(e) => setBookingForm({ ...bookingForm, room_id: e.target.value })}>
                <option value="">Select room/table</option>
                {rooms.map((r) => <option key={r.id} value={r.id}>{r.name}</option>)}
              </select>
              <input className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" placeholder="customer name" value={bookingForm.customer_name} onChange={(e) => setBookingForm({ ...bookingForm, customer_name: e.target.value })} />
              <input className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" placeholder="customer email" value={bookingForm.customer_email} onChange={(e) => setBookingForm({ ...bookingForm, customer_email: e.target.value })} />
              <input className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" type="number" min="1" value={bookingForm.party_size} onChange={(e) => setBookingForm({ ...bookingForm, party_size: Number(e.target.value) })} />
              <input className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" type="datetime-local" value={bookingForm.start_at} onChange={(e) => setBookingForm({ ...bookingForm, start_at: e.target.value })} />
              <input className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" type="datetime-local" value={bookingForm.end_at} onChange={(e) => setBookingForm({ ...bookingForm, end_at: e.target.value })} />
              <textarea className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" placeholder="notes" value={bookingForm.notes} onChange={(e) => setBookingForm({ ...bookingForm, notes: e.target.value })} />
              <button className="rounded-md bg-black px-4 py-2 text-white">Create booking</button>
            </form>

            <div className="rounded-lg border border-slate-700 bg-slate-900 p-4">
              <h3 className="mb-3 text-lg font-semibold">Booking Queue</h3>
              <div className="space-y-2">
                {bookings.map((b) => (
                  <div key={b.id} className="rounded border border-slate-700 bg-slate-800 p-2 text-sm">
                    <p className="font-medium">{b.customer_name} · {b.status}</p>
                    <p className="text-xs text-slate-300">{b.script_title} in {b.room_name}</p>
                    <p className="text-xs text-slate-400">{new Date(b.start_at).toLocaleString()} - {new Date(b.end_at).toLocaleString()}</p>
                    {['admin', 'host'].includes(user?.role) && (
                      <div className="mt-2 flex gap-2">
                        {['pending', 'confirmed', 'cancelled', 'completed'].map((state) => (
                          <button key={state} className="rounded bg-black px-2 py-1 text-xs text-white" onClick={() => updateBookingStatus(b, state)}>{state}</button>
                        ))}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          </section>
        )}

        {activeTab === 'forum' && (
          <section className="grid gap-4 md:grid-cols-3">
            <div className="rounded-lg border border-slate-700 bg-slate-900 p-4 space-y-3">
              <h2 className="text-lg font-semibold">Sections</h2>
              {canModerate && (
                <form onSubmit={createSection} className="space-y-2">
                  <input className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" placeholder="section name" value={sectionForm.name} onChange={(e) => setSectionForm({ ...sectionForm, name: e.target.value })} />
                  <input className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" placeholder="description" value={sectionForm.description} onChange={(e) => setSectionForm({ ...sectionForm, description: e.target.value })} />
                  <button className="rounded-md bg-black px-3 py-1 text-white">Create section</button>
                </form>
              )}
              <ul className="space-y-1">
                {sections.map((s) => (
                  <li key={s.id} className={classes('rounded border p-2 text-sm', selectedSection === s.id ? 'border-white bg-slate-700' : 'border-slate-700 bg-slate-800')}>
                    <button className="w-full text-left" onClick={() => { setSelectedSection(s.id); setSelectedThread(''); }}>
                      {s.name}
                      <span className="ml-2 text-xs text-slate-300">{s.pinned ? 'pinned' : ''} {s.locked ? 'locked' : ''}</span>
                    </button>
                    {canModerate && (
                      <div className="mt-2 flex gap-2">
                        <button className="rounded bg-black px-2 py-1 text-xs" onClick={() => moderate('sections', s.id, 'pinned', !s.pinned)}>pin</button>
                        <button className="rounded bg-black px-2 py-1 text-xs" onClick={() => moderate('sections', s.id, 'locked', !s.locked)}>lock</button>
                      </div>
                    )}
                  </li>
                ))}
              </ul>
            </div>

            <div className="rounded-lg border border-slate-700 bg-slate-900 p-4 space-y-3">
              <h3 className="text-lg font-semibold">Threads</h3>
              <form onSubmit={createThread} className="space-y-2">
                <input className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" placeholder="thread title" value={threadForm.title} onChange={(e) => setThreadForm({ ...threadForm, title: e.target.value })} />
                <textarea className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" placeholder="thread body" value={threadForm.body} onChange={(e) => setThreadForm({ ...threadForm, body: e.target.value })} />
                <button className="rounded-md bg-black px-3 py-1 text-white">Create thread</button>
              </form>
              <ul className="space-y-1">
                {threads.map((t) => (
                  <li key={t.id} className={classes('rounded border p-2 text-sm', selectedThread === t.id ? 'border-white bg-slate-700' : 'border-slate-700 bg-slate-800')}>
                    <button className="w-full text-left" onClick={() => setSelectedThread(t.id)}>
                      {t.title}
                      <span className="ml-2 text-xs text-slate-300">{t.pinned ? 'pinned' : ''} {t.locked ? 'locked' : ''}</span>
                    </button>
                    {canModerate && (
                      <div className="mt-2 flex gap-2">
                        <button className="rounded bg-black px-2 py-1 text-xs" onClick={() => moderate('threads', t.id, 'featured', !t.featured)}>feature</button>
                        <button className="rounded bg-black px-2 py-1 text-xs" onClick={() => moderate('threads', t.id, 'archived', !t.archived)}>archive</button>
                      </div>
                    )}
                  </li>
                ))}
              </ul>
            </div>

            <div className="rounded-lg border border-slate-700 bg-slate-900 p-4 space-y-3">
              <h3 className="text-lg font-semibold">Nested Replies</h3>
              <form onSubmit={createPost} className="space-y-2">
                <select className="w-full rounded border border-slate-600 bg-slate-800 px-2 py-1" value={postForm.parent_post_id} onChange={(e) => setPostForm({ ...postForm, parent_post_id: e.target.value })}>
                  <option value="">Top-level reply</option>
