  try {
    const p = request.body || {};
    requireBodyFields(p, ['subject_id', 'round_key', 'metrics', 'weights']);
    const score = weightedAggregation({
      metrics: p.metrics,
      weights: p.weights,
      strategy: p.strategy || 'drop',
      mappingRules: p.mapping_rules || {},
    });
    const merged = mergeRounds([...(p.previous_round_scores || []), score]);
    const ledger = await query(
      `INSERT INTO scoring_adjustment_ledger
       (subject_id, round_key, score_before, score_after, strategy, mapping_rule, weights, details, created_by_user_id)
       VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9)
       RETURNING *`,
      [
        p.subject_id,
        p.round_key,
        p.previous_score ?? null,
        merged,
        p.strategy || 'drop',
        p.mapping_rules || {},
        p.weights,
        { current_score: score, previous_round_scores: p.previous_round_scores || [] },
        request.user.id,
      ]
    );
    return reply.code(201).send({ current_score: score, merged_score: merged, ledger: ledger.rows[0] });
  } catch (e) {
    return reply.code(400).send({ error: e.message });
  }
});

