function buildSectionHierarchy(items) {
  const byId = new Map(items.map((item) => [item.id, { ...item, children: [] }]));
  const roots = [];
  for (const item of byId.values()) {
    if (item.parent_section_id && byId.has(item.parent_section_id)) {
